// HasParts applies the HasEdge predicate on the "parts" edge.
func HasParts() predicate.RepairJob {
	return predicate.RepairJob(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.O2M, false, PartsTable, PartsColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasPartsWith applies the HasEdge predicate on the "parts" edge with a given conditions (other predicates).
func HasPartsWith(preds ...predicate.RepairJobPart) predicate.RepairJob {
	return predicate.RepairJob(func(s *sql.Selector) {
		step := newPartsStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// HasEvents applies the HasEdge predicate on the "events" edge.
func HasEvents() predicate.RepairJob {
	return predicate.RepairJob(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.O2M, false, EventsTable, EventsColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasEventsWith applies the HasEdge predicate on the "events" edge with a given conditions (other predicates).
func HasEventsWith(preds ...predicate.RepairJobEvent) predicate.RepairJob {
	return predicate.RepairJob(func(s *sql.Selector) {
		step := newEventsStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.RepairJob) predicate.RepairJob {
	return predicate.RepairJob(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.RepairJob) predicate.RepairJob {
	return predicate.RepairJob(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.RepairJob) predicate.RepairJob {
	return predicate.RepairJob(sql.NotPredicates(p))
}
